import{k as e,p as t,u as n}from"./chunks/runtime-core.esm-bundler.PK8HO-US.js";import{t as r}from"./chunks/plugin-vue_export-helper.DrfHhw6c.js";import{a as i,i as a,n as o,r as s,t as c}from"./chunks/javadoc.By8MmAW1.js";const l=JSON.parse(`{"title":"Генерація джерел в IntelliJ IDEA","description":"Посібник зі створення джерел Minecraft в IntelliJ IDEA.","frontmatter":{"title":"Генерація джерел в IntelliJ IDEA","description":"Посібник зі створення джерел Minecraft в IntelliJ IDEA.","authors":["dicedpixels"],"prev":{"text":"Запуск гри в IntelliJ IDEA","link":"./launching-the-game"},"next":{"text":"Збирання мода в IntelliJ IDEA","link":"./building-a-mod"},"files":[]},"headers":[],"relativePath":"uk_ua/develop/getting-started/intellij-idea/generating-sources.md","filePath":"translated/uk_ua/develop/getting-started/intellij-idea/generating-sources.md","lastUpdated":1774518827000}`);var u={name:`uk_ua/develop/getting-started/intellij-idea/generating-sources.md`};function d(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="h1" tabindex="-1">Генерація джерел в IntelliJ IDEA <a class="header-anchor" href="#h1" aria-label="Permalink to “Генерація джерел в IntelliJ IDEA”">​</a></h1><p>Інструментарій Fabric дає вам доступ до вихідного коду Minecraft, генеруючи його локально, і ви можете використовувати IntelliJ IDEA для зручної навігації по ньому. Щоб згенерувати джерела, потрібно запустити завдання Gradle <code>genSources</code>.</p><p>Це можна зробити з панелі Gradle, запустивши завдання <code>genSources</code> у <strong>Tasks</strong> &gt; <strong><code>fabric</code></strong>: <img src="/assets/develop/getting-started/intellij/gradle-gensources.png" alt="Завдання genSources в панелі Gradle" loading="lazy"></p><p>Або ви також можете запустити команду з термінала:</p><div class="language-sh"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">./gradlew</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> genSources</span></span></code></pre></div><p><img src="/assets/develop/getting-started/intellij/terminal-gensources.png" alt="Завдання genSources в терміналі" loading="lazy"></p><h2 id="attaching-sources" tabindex="-1">Додавання джерел <a class="header-anchor" href="#attaching-sources" aria-label="Permalink to “Додавання джерел”">​</a></h2><p>Для IntelliJ потрібен один додатковий крок — приєднання згенерованих джерел до проєкту.</p><p>Для цього відкрийте будь-який клас Minecraft. Ви можете <kbd>Ctrl</kbd> + натиснути, щоб перейти до визначення, яке відкриває клас, або скористайтеся функцією «Search everywhere», щоб відкрити клас.</p><p>Відкриймо <code>MinecraftServer.class</code> як приклад. Тепер ви повинні побачити синій банер угорі з посиланням «<strong>Choose Sources…</strong>».</p><p><img src="/assets/develop/getting-started/intellij/choose-sources.png" alt="Вибір джерел" loading="lazy"></p><p>Натисніть «<strong>Choose Sources…</strong>», щоб відкрити діалогове вікно вибору файлів. Усталено це діалогове вікно відкриється у правильному місці згенерованих джерел.</p><p>Виберіть файл, який закінчується на <strong><code>-sources</code></strong>, і натисніть <strong>Open</strong>, щоб підтвердити вибір.</p><p><img src="/assets/develop/getting-started/intellij/choose-sources-dialog.png" alt="Діалогове вікно вибору джерел" loading="lazy"></p><p>Тепер ви повинні мати можливість шукати посилання. Якщо ви використовуєте набір мапінгів, який містить Javadocs, як-от <a href="https://parchmentmc.org/" target="_blank" rel="noreferrer">Parchment</a> (для мапінгів Mojang) або Yarn, тепер ви також повинні бачити Javadoc.</p><p><img src="/assets/develop/getting-started/intellij/javadoc.png" alt="Коментарі Javadoc у джерелах" loading="lazy"></p>`,16)]])}var f=r(u,[[`render`,d]]);export{l as __pageData,f as default};